struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // Write packet_id using the stream
        stream << packet_id;

        // Write username with length prefix using prefixed adaptor
        stream << prefixed(username);

        // Write scores count first, then elements using prefixed adaptor
        stream << prefixed(scores);

        // Write metadata as null-terminated string using null_terminated adaptor
        stream << null_terminated(metadata);
    }
};

