```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create a hexi::deserializer object from the buffer
    hexi::deserializer deserializer(buffer);

    NetworkPacket packet;

    // Read packet_id using operator>>
    deserializer >> packet.packet_id;

    // Read username using prefixed adaptor
    deserializer >> hexi::prefixed(packet.username);

    // Read score count and use read_container to read scores vector
    uint32_t score_count;
    deserializer >> score_count;

    // Read container expects the container and the count
    deserializer.read_container(packet.scores, score_count);

    // Read metadata string as null-terminated
    deserializer >> hexi::null_terminated(packet.metadata);

    // Skip any remaining padding bytes
    deserializer.skip(deserializer.total_read() >= buffer.size() ? 0 : (buffer.size() - deserializer.total_read()));

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    // Create a hexi::deserializer object from the buffer
    hexi::deserializer deserializer(buffer);

    PacketInfo info;

    // Use span() for packet_id (zero-copy view of first 4 bytes)
    std::span<const uint8_t> id_span = deserializer.span(4);
    if (id_span.size() == 4) {
        info.packet_id = *reinterpret_cast<const uint32_t*>(id_span.data());
    }

    // Read username using prefixed adaptor to get string_view
    deserializer >> hexi::prefixed(info.username);

    // Skip the scores vector (read count, then skip data)
    uint32_t score_count;
    deserializer >> score_count;
    deserializer.skip(score_count * sizeof(uint32_t));

    return info;
}
```

## Key Implementation Details:

### `deserialize_packet` Function:
1. **Deserialization Object**: Creates a `hexi::deserializer` from the input buffer
2. **Packet ID**: Uses `operator>>` to directly read the `uint32_t packet_id`
3. **Username**: Uses `hexi::prefixed` adaptor which handles the length-prefixed string format
4. **Scores Vector**: 
   - First reads the count using `operator>>`
   - Then uses `read_container` to populate the vector with the specified number of elements
5. **Metadata**: Uses `hexi::null_terminated` adaptor for the null-terminated string
6. **Padding**: Skips any remaining bytes using the `skip` method

### `extract_packet_info` Function:
1. **Zero-Copy Packet ID**: Uses `span()` method to get a direct view of the first 4 bytes
2. **Username**: Uses `hexi::prefixed` adaptor which returns a `std::string_view` without copying
3. **Scores Skipping**: 
   - Reads the count using `operator>>`
   - Skips the entire scores section using `skip()` with the calculated byte size
4. **Efficient**: Only reads necessary information without full deserialization

Both implementations follow the Hexi library patterns shown in the reference materials and handle the binary data format correctly according to the specified packet structure.

