#include <string_view>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Serialization: write fields with conditional_reverse for endianness
        adaptor(sensor_id);

        for (auto& temp : temperatures) {
            const auto converted = hexi::endian::conditional_reverse(temp, 
                                                                    std::endian::native, 
                                                                    std::endian::little);
            adaptor(converted);
        }

        const auto converted_pressure = hexi::endian::conditional_reverse(pressure, 
                                                                          std::endian::native, 
                                                                          std::endian::little);
        adaptor(converted_pressure);
    }

    void serialise(auto& adaptor) {
        // Deserialization: read fields and convert with little_to_native_inplace
        adaptor(sensor_id);

        for (auto& temp : temperatures) {
            adaptor(temp);
            hexi::endian::little_to_native_inplace(temp);
        }

        adaptor(pressure);
        hexi::endian::little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);

    // Use stream's serialise method to serialize the entire structure
    adaptor.serialise(data);

    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    MeasurementData result;
    hexi::buffer_adaptor adaptor(buffer);

    // Use stream's deserialise method to deserialize the entire structure
    adaptor.deserialise(result);

    return result;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    SensorInfo info;
    hexi::buffer_adaptor adaptor(buffer);

    // Use view to extract null-terminated sensor name string
    info.sensor_name = adaptor.view();

    // Use enforce_read_bounds to check if there's enough data for sensor_id
    adaptor.enforce_read_bounds(sizeof(uint32_t));

    // Read sensor_id directly
    info.sensor_id = 0; // Initialize in case error occurs
    adaptor.read(&info.sensor_id, sizeof(uint32_t));

    // Skip remaining data
    const auto remaining = adaptor.size();
    if (remaining > 0) {
        adaptor.skip(remaining);
    }

    return info;
}
